 1  import { verify } from 'jsonwebtoken';
 2  import type { Request, Response, NextFunction } from 'express';
 3  
 4  interface JWTPayload {
 5    userId: string;
 6    role: 'admin' | 'user';
 7    exp: number;
 8  }
 9  
10  const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret';
11  
12  export function authMiddleware(req: Request, _res: Response, next: NextFunction): void {
13    const header = req.headers.authorization;
14    if (!header?.startsWith('Bearer ')) {
15      throw new Error('Missing or invalid Authorization header');
16    }
17    const token = header.slice(7);
18    const payload = verify(token, JWT_SECRET) as JWTPayload;
19    req.user = { id: payload.userId, role: payload.role };
20    next();
21  }
22  
23  export function requireAdmin(req: Request, _res: Response, next: NextFunction): void {
24    if (req.user?.role !== 'admin') {
25      throw new Error('Admin access required');
26    }
27    next();
28  }
